class alertsraised_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('alertsraised page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('submit', 'empty.gif');
		$this->addGlobalSubmit();
		$idalertsraised = $fs->addElement('text', 'idalertsraised', array('size' => 10, 'maxlength' => 10) )
			->setLabel( 'Index' )
			->addRule('required', 'idalertsraised Field Required' );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'username' => $_SERVER['PHP_AUTH_USER'] ) ) );
		$username = $fs->addElement('text', 'username', array('size' => 45, 'maxlength' => 45) )
			->setLabel( 'User' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
;
		$f_date = date("Y-m-d H:i:s" );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'lastupdate' => $f_date ) ) );
		$lastupdate = $fs->addElement('text', 'lastupdate', array('size' => 17, 'maxlength' => 17) )
			->setLabel( 'Last Updated' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
;
		$f_date = date("Y-m-d H:i:s" );
		$this->form->addDataSource(new HTML_QuickForm2_DataSource_Array(array( 'raisedtimestamp' => $f_date ) ) );
		$raisedtimestamp = $fs->addElement('text', 'raisedtimestamp', array('size' => 17, 'maxlength' => 17) )
			->setLabel( 'Alert Raised' )
			->addFilter( 'trim' )
			->addFilter( 'strtoupper' )
			->addRule('required', 'raisedtimestamp Field Required' );
	}
}
